/* DMA Controller API - dma.h */
#ifndef DMA_H
#define DMA_H

#include <stdint.h>

typedef void (*dma_callback_t)(uint8_t channel, uint8_t status);

typedef struct {
    uint32_t src_addr;
    uint32_t dst_addr;
    uint16_t length;
    uint8_t  src_inc;    /* 1 = auto-increment source address */
    uint8_t  dst_inc;    /* 1 = auto-increment dest address */
    uint8_t  burst_size; /* transfer unit: 1, 4, or 16 bytes */
    dma_callback_t complete_cb;
} dma_transfer_t;

int  dma_init(uint8_t channel);
int  dma_start(uint8_t channel, const dma_transfer_t *xfer);
void dma_abort(uint8_t channel);
uint16_t dma_bytes_remaining(uint8_t channel);

#endif /* DMA_H */

after_code:
/* DMA Controller API - dma.h */
#ifndef DMA_H
#define DMA_H

#include <stdint.h>

typedef void (*dma_callback_t)(uint8_t channel, uint8_t status);

/* BREAKING: priority field inserted between dst_inc and burst_size;
   static initializers using positional field order assign wrong values
   to burst_size and complete_cb, causing silent DMA misconfiguration. */
typedef struct {
    uint32_t src_addr;
    uint32_t dst_addr;
    uint16_t length;
    uint8_t  src_inc;
    uint8_t  dst_inc;
    uint8_t  priority;   /* NEW: 0=low, 1=medium, 2=high */
    uint8_t  burst_size;
    uint8_t  reserved[2];
    dma_callback_t complete_cb;
} dma_transfer_t;

int  dma_init(uint8_t channel);
int  dma_start(uint8_t channel, const dma_transfer_t *xfer);
void dma_abort(uint8_t channel);
uint16_t dma_bytes_remaining(uint8_t channel);

#endif /* DMA_H */

